-- AL Governador: Renan Filho fecha residuos SAPL por metadata oficial
-- Fonte: fonte interna de curadoria

DO $$
BEGIN
  IF NOT EXISTS (SELECT 1 FROM candidatos WHERE slug = 'renan-filho' AND publicavel = true) THEN
    RAISE EXCEPTION 'renan-filho nao encontrado ou nao publicavel';
  END IF;
END $$;

