WITH target AS (
  SELECT c.id AS candidato_id, seed.*, (
    SELECT hp.id FROM historico_politico hp
    WHERE hp.candidato_id = c.id AND hp.tipo_evento = 'mandato' AND UPPER(COALESCE(hp.estado,'')) = 'AL'
      AND (hp.cargo ILIKE '%Governador%' OR hp.cargo_canonico = 'Governador')
      AND COALESCE(hp.periodo_inicio,9999) <= EXTRACT(YEAR FROM seed.data_norma::date)::int
      AND COALESCE(hp.periodo_fim,9999) >= EXTRACT(YEAR FROM seed.data_norma::date)::int
    ORDER BY hp.periodo_inicio DESC NULLS LAST, hp.id LIMIT 1
  ) AS historico_politico_id
  FROM candidatos c CROSS JOIN _seed_renan_filho_al_sapl_metadata_residual seed
  WHERE c.slug = 'renan-filho' AND c.publicavel = true
)
INSERT INTO legislacao_mandato_executivo (candidato_id,historico_politico_id,tipo_relacao,esfera,uf_norma,tipo_norma,numero,ano,data_norma,ementa,signatario,autoridade_papel,fonte_primaria_url,fonte_primaria_titulo,fonte_tramitacao_url,identificador_fonte,metadata)
SELECT candidato_id,historico_politico_id,tipo_relacao,esfera,uf_norma,tipo_norma,numero,ano,data_norma::date,ementa,signatario,autoridade_papel,fonte_primaria_url,fonte_primaria_titulo,fonte_tramitacao_url,identificador_fonte,metadata
FROM target
WHERE historico_politico_id IS NOT NULL
  AND NOT EXISTS (SELECT 1 FROM legislacao_mandato_executivo lme WHERE lme.candidato_id = target.candidato_id AND lme.identificador_fonte = target.identificador_fonte);

DO $$
DECLARE renan_id uuid; total_count int; delta_count int;
BEGIN
  SELECT id INTO renan_id FROM candidatos WHERE slug = 'renan-filho' AND publicavel = true;
  SELECT count(*) INTO total_count FROM legislacao_mandato_executivo WHERE candidato_id = renan_id;
  SELECT count(*) INTO delta_count FROM legislacao_mandato_executivo WHERE candidato_id = renan_id AND metadata ->> 'coverage_id' = 'renan-filho-al-sapl-inventario-oficial-2015-2022-20260704';
  IF total_count <> 720 THEN RAISE EXCEPTION 'renan LME total esperado 720, encontrado %', total_count; END IF;
  IF delta_count <> 22 THEN RAISE EXCEPTION 'renan LME delta esperado 22, encontrado %', delta_count; END IF;
END $$;
